"""Tests for databricks.vector_search.client.VectorSearchClient."""

from unittest.mock import patch

import pytest

from databricks.vector_search.client import VectorSearchClient
from databricks.vector_search.exceptions import InvalidInputException, NotFound
from databricks.vector_search.index import VectorSearchIndex


class TestVectorSearchClientInit:
    def test_pat_credentials_stored(self):
        client = VectorSearchClient(
            workspace_url="https://ws",
            personal_access_token="dapi...",
            disable_notice=True,
        )
        assert client.workspace_url == "https://ws"
        assert client.personal_access_token == "dapi..."
        assert client._using_user_passed_credentials is True
        assert client._is_notebook_pat is False

    def test_service_principal_credentials_stored(self):
        client = VectorSearchClient(
            workspace_url="https://ws",
            service_principal_client_id="id",
            service_principal_client_secret="secret",
            disable_notice=True,
        )
        assert client.service_principal_client_id == "id"
        assert client.service_principal_client_secret == "secret"
        assert client._using_user_passed_credentials is True

    def test_azure_login_id_defaults_to_public(self):
        client = VectorSearchClient(
            workspace_url="https://ws",
            personal_access_token="x",
            disable_notice=True,
        )
        assert client.azure_login_id == "2ff814a6-3304-4ab8-85cb-cd0e6f879c1d"

    def test_pat_missing_workspace_url_raises_invalid_input(self):
        with pytest.raises(InvalidInputException, match="Workspace URL is required"):
            VectorSearchClient(personal_access_token="dapi", disable_notice=True)

    def test_no_credentials_raises_invalid_input(self):
        # With user-passed creds path off and a workspace_url provided, validate()
        # raises because neither PAT nor SP are set.
        client = VectorSearchClient.__new__(VectorSearchClient)
        client.workspace_url = "https://ws"
        client.personal_access_token = None
        client.service_principal_client_id = None
        client.service_principal_client_secret = None
        client._using_user_passed_credentials = False
        client._is_notebook_pat = False
        with pytest.raises(InvalidInputException, match="personal access token or service principal"):
            client.validate(disable_notice=True)


class TestGetTokenForRequest:
    def test_pat_returns_pat(self):
        client = VectorSearchClient(
            workspace_url="https://ws",
            personal_access_token="pat-value",
            disable_notice=True,
        )
        assert client._get_token_for_request() == "pat-value"

    @patch("databricks.vector_search.client.OAuthTokenUtils.get_oauth_token")
    def test_sp_fetches_and_caches_oauth_token(self, mock_oauth):
        mock_oauth.return_value = {"access_token": "oauth-tok", "expires_in": 3600}
        client = VectorSearchClient(
            workspace_url="https://ws",
            service_principal_client_id="id",
            service_principal_client_secret="secret",
            disable_notice=True,
        )
        token1 = client._get_token_for_request()
        token2 = client._get_token_for_request()
        assert token1 == "oauth-tok"
        assert token2 == "oauth-tok"
        # Only one network call thanks to in-memory cache.
        mock_oauth.assert_called_once()

    @patch("databricks.vector_search.client.OAuthTokenUtils.get_azure_oauth_token")
    def test_azure_sp_routes_through_azure_oauth(self, mock_azure):
        mock_azure.return_value = {"access_token": "azure-tok", "expires_in": 3600}
        client = VectorSearchClient(
            workspace_url="https://ws",
            service_principal_client_id="id",
            service_principal_client_secret="secret",
            azure_tenant_id="tenant",
            disable_notice=True,
        )
        assert client._get_token_for_request() == "azure-tok"
        mock_azure.assert_called_once()

    def test_no_credentials_raises(self):
        client = VectorSearchClient.__new__(VectorSearchClient)
        client.workspace_url = "https://ws"
        client.personal_access_token = None
        client.service_principal_client_id = None
        client.service_principal_client_secret = None
        client.azure_tenant_id = None
        client._using_user_passed_credentials = True
        client._control_plane_oauth_token = None
        client._control_plane_oauth_token_expiry_ts = None
        client.credential_strategy = None
        with pytest.raises(Exception, match="service principal or PAT"):
            client._get_token_for_request()


class TestEndpointCRUD:
    @patch("databricks.vector_search.client.RequestUtils.issue_request")
    def test_create_endpoint_posts_payload(self, mock_req, vsc_with_pat, workspace_url):
        mock_req.return_value = {"endpoint": {}}
        vsc_with_pat.create_endpoint("my-ep", endpoint_type="STANDARD")
        call = mock_req.call_args.kwargs
        assert call["method"] == "POST"
        assert call["url"] == f"{workspace_url}/api/2.0/vector-search/endpoints"
        assert call["json"] == {"name": "my-ep", "endpoint_type": "STANDARD"}

    def test_create_endpoint_rejects_both_policy_ids(self, vsc_with_pat):
        with pytest.raises(InvalidInputException):
            vsc_with_pat.create_endpoint("ep", budget_policy_id="b", usage_policy_id="u")

    def test_create_endpoint_rejects_non_int_target_qps(self, vsc_with_pat):
        with pytest.raises(InvalidInputException, match="must be an integer"):
            vsc_with_pat.create_endpoint("ep", target_qps="big")

    def test_create_endpoint_rejects_non_positive_target_qps(self, vsc_with_pat):
        with pytest.raises(InvalidInputException, match="positive integer"):
            vsc_with_pat.create_endpoint("ep", target_qps=0)

    @patch("databricks.vector_search.client.RequestUtils.issue_request")
    def test_create_endpoint_includes_target_qps_and_policy(self, mock_req, vsc_with_pat):
        mock_req.return_value = {}
        vsc_with_pat.create_endpoint("ep", target_qps=50, usage_policy_id="up")
        body = mock_req.call_args.kwargs["json"]
        assert body["target_qps"] == 50
        assert body["budget_policy_id"] == "up"

    @patch("databricks.vector_search.client.RequestUtils.issue_request")
    def test_get_endpoint_hits_endpoint_url(self, mock_req, vsc_with_pat, workspace_url):
        mock_req.return_value = {"endpoint": {"state": "ONLINE"}}
        result = vsc_with_pat.get_endpoint("my-ep")
        assert result == {"endpoint": {"state": "ONLINE"}}
        assert mock_req.call_args.kwargs["url"] == (f"{workspace_url}/api/2.0/vector-search/endpoints/my-ep")
        assert mock_req.call_args.kwargs["method"] == "GET"

    @patch("databricks.vector_search.client.RequestUtils.issue_request")
    def test_endpoint_exists_true_on_success(self, mock_req, vsc_with_pat):
        mock_req.return_value = {}
        assert vsc_with_pat.endpoint_exists("ep") is True

    @patch("databricks.vector_search.client.RequestUtils.issue_request")
    def test_endpoint_exists_false_on_not_found(self, mock_req, vsc_with_pat):
        mock_req.side_effect = NotFound("nope", status_code=404)
        assert vsc_with_pat.endpoint_exists("ep") is False

    @patch("databricks.vector_search.client.RequestUtils.issue_request")
    def test_list_endpoints_calls_endpoints_url(self, mock_req, vsc_with_pat, workspace_url):
        mock_req.return_value = {"endpoints": []}
        vsc_with_pat.list_endpoints()
        assert mock_req.call_args.kwargs["url"] == (f"{workspace_url}/api/2.0/vector-search/endpoints")

    @patch("databricks.vector_search.client.RequestUtils.issue_request")
    def test_delete_endpoint_issues_delete(self, mock_req, vsc_with_pat, workspace_url):
        mock_req.return_value = {}
        vsc_with_pat.delete_endpoint("my-ep")
        call = mock_req.call_args.kwargs
        assert call["method"] == "DELETE"
        assert call["url"] == f"{workspace_url}/api/2.0/vector-search/endpoints/my-ep"

    @patch("databricks.vector_search.client.RequestUtils.issue_request")
    def test_update_endpoint_target_qps_payload(self, mock_req, vsc_with_pat, workspace_url):
        mock_req.return_value = {}
        vsc_with_pat.update_endpoint("ep", target_qps=200)
        call = mock_req.call_args.kwargs
        assert call["method"] == "PATCH"
        assert call["url"] == f"{workspace_url}/api/2.0/vector-search/endpoints/ep"
        assert call["json"] == {"target_qps": 200}

    @patch("databricks.vector_search.client.RequestUtils.issue_request")
    def test_update_endpoint_accepts_minus_one_reset_literal(self, mock_req, vsc_with_pat):
        # The validator still accepts -1 (the internal reset sentinel) for
        # back-compat even though it's no longer advertised as a public API.
        mock_req.return_value = {}
        vsc_with_pat.update_endpoint("ep", target_qps=-1)
        assert mock_req.call_args.kwargs["json"] == {"target_qps": -1}

    def test_update_endpoint_rejects_empty_name(self, vsc_with_pat):
        with pytest.raises(InvalidInputException, match="Endpoint name"):
            vsc_with_pat.update_endpoint(name="")

    def test_update_endpoint_rejects_invalid_target_qps(self, vsc_with_pat):
        with pytest.raises(InvalidInputException, match="positive integer"):
            vsc_with_pat.update_endpoint("ep", target_qps=0)

    @patch("databricks.vector_search.client.RequestUtils.issue_request")
    def test_update_endpoint_budget_policy_uses_budget_field(self, mock_req, vsc_with_pat, workspace_url):
        mock_req.return_value = {}
        vsc_with_pat.update_endpoint_budget_policy("ep", usage_policy_id="up")
        call = mock_req.call_args.kwargs
        assert call["url"] == (f"{workspace_url}/api/2.0/vector-search/endpoints/ep/budget-policy")
        assert call["json"] == {"budget_policy_id": "up"}

    def test_update_endpoint_budget_policy_rejects_both(self, vsc_with_pat):
        with pytest.raises(InvalidInputException):
            vsc_with_pat.update_endpoint_budget_policy("ep", budget_policy_id="b", usage_policy_id="u")

    def test_update_endpoint_budget_policy_rejects_neither(self, vsc_with_pat):
        with pytest.raises(InvalidInputException):
            vsc_with_pat.update_endpoint_budget_policy("ep")


class TestWaitForEndpoint:
    @patch("databricks.vector_search.client.time.sleep")
    @patch("databricks.vector_search.client.RequestUtils.issue_request")
    def test_polls_until_online(self, mock_req, mock_sleep, vsc_with_pat):
        mock_req.side_effect = [
            {"endpoint_status": {"state": "PROVISIONING"}},
            {"endpoint_status": {"state": "ONLINE"}},
        ]
        vsc_with_pat.wait_for_endpoint("ep")
        assert mock_req.call_count == 2

    @patch("databricks.vector_search.client.time.sleep")
    @patch("databricks.vector_search.client.RequestUtils.issue_request")
    def test_raises_on_offline(self, mock_req, _sleep, vsc_with_pat):
        mock_req.return_value = {"endpoint_status": {"state": "OFFLINE"}}
        with pytest.raises(Exception, match="OFFLINE"):
            vsc_with_pat.wait_for_endpoint("ep")


class TestIndexCRUD:
    @patch("databricks.vector_search.client.RequestUtils.issue_request")
    def test_create_delta_sync_index_returns_index(self, mock_req, vsc_with_pat):
        mock_req.return_value = {
            "name": "cat.sch.idx",
            "status": {"index_url": "https://dp/index"},
        }
        idx = vsc_with_pat.create_delta_sync_index(
            endpoint_name="ep",
            index_name="cat.sch.idx",
            primary_key="id",
            source_table_name="cat.sch.source",
            pipeline_type="TRIGGERED",
            embedding_dimension=768,
            embedding_vector_column="emb",
        )
        assert isinstance(idx, VectorSearchIndex)
        body = mock_req.call_args.kwargs["json"]
        assert body["name"] == "cat.sch.idx"
        assert body["index_type"] == "DELTA_SYNC"
        assert body["delta_sync_index_spec"]["pipeline_type"] == "TRIGGERED"

    def test_create_delta_sync_index_requires_embedding_config(self, vsc_with_pat):
        with pytest.raises(InvalidInputException, match="embedding_source_column or embedding_vector_column"):
            vsc_with_pat.create_delta_sync_index(
                endpoint_name="ep",
                index_name="i",
                primary_key="id",
                source_table_name="src",
                pipeline_type="TRIGGERED",
            )

    def test_create_delta_sync_index_rejects_both_policy_ids(self, vsc_with_pat):
        with pytest.raises(InvalidInputException):
            vsc_with_pat.create_delta_sync_index(
                endpoint_name="ep",
                index_name="i",
                primary_key="id",
                source_table_name="src",
                pipeline_type="TRIGGERED",
                embedding_dimension=4,
                embedding_vector_column="v",
                budget_policy_id="b",
                usage_policy_id="u",
            )

    @patch("databricks.vector_search.client.RequestUtils.issue_request")
    def test_create_direct_access_index_returns_index(self, mock_req, vsc_with_pat):
        mock_req.return_value = {
            "name": "cat.sch.da",
            "status": {"index_url": "https://dp/da"},
        }
        idx = vsc_with_pat.create_direct_access_index(
            endpoint_name="ep",
            index_name="cat.sch.da",
            primary_key="id",
            embedding_dimension=8,
            embedding_vector_column="v",
            schema={"id": "integer", "v": "array<float>"},
        )
        assert isinstance(idx, VectorSearchIndex)
        body = mock_req.call_args.kwargs["json"]
        assert body["index_type"] == "DIRECT_ACCESS"
        spec = body["direct_access_index_spec"]
        assert spec["embedding_vector_columns"][0]["embedding_dimension"] == 8

    def test_create_direct_access_index_requires_schema(self, vsc_with_pat):
        with pytest.raises(AssertionError):
            vsc_with_pat.create_direct_access_index(
                endpoint_name="ep",
                index_name="da",
                primary_key="id",
                embedding_dimension=4,
                embedding_vector_column="v",
                schema=None,
            )

    @patch("databricks.vector_search.client.RequestUtils.issue_request")
    def test_get_index_returns_index_instance(self, mock_req, vsc_with_pat):
        mock_req.return_value = {
            "status": {"index_url": "https://dp/idx"},
            "endpoint_name": "ep",
        }
        idx = vsc_with_pat.get_index(endpoint_name="ep", index_name="cat.sch.idx")
        assert isinstance(idx, VectorSearchIndex)
        assert idx.name == "cat.sch.idx"

    def test_get_index_requires_index_name(self, vsc_with_pat):
        with pytest.raises(AssertionError):
            vsc_with_pat.get_index(endpoint_name="ep", index_name=None)

    @patch("databricks.vector_search.client.RequestUtils.issue_request")
    def test_index_exists_false_on_not_found(self, mock_req, vsc_with_pat):
        mock_req.side_effect = NotFound("nope", status_code=404)
        assert vsc_with_pat.index_exists(index_name="cat.sch.idx") is False

    @patch("databricks.vector_search.client.RequestUtils.issue_request")
    def test_index_exists_true_on_success(self, mock_req, vsc_with_pat):
        mock_req.return_value = {"status": {"index_url": "https://x"}}
        assert vsc_with_pat.index_exists(index_name="cat.sch.idx") is True

    @patch("databricks.vector_search.client.RequestUtils.issue_request")
    def test_list_indexes_url(self, mock_req, vsc_with_pat, workspace_url):
        mock_req.return_value = {"indexes": []}
        vsc_with_pat.list_indexes("ep")
        assert mock_req.call_args.kwargs["url"] == (f"{workspace_url}/api/2.0/vector-search/endpoints/ep/indexes")

    @patch("databricks.vector_search.client.RequestUtils.issue_request")
    def test_delete_index_url_with_endpoint(self, mock_req, vsc_with_pat, workspace_url):
        mock_req.return_value = {}
        vsc_with_pat.delete_index(endpoint_name="ep", index_name="i")
        call = mock_req.call_args.kwargs
        assert call["method"] == "DELETE"
        assert call["url"] == (f"{workspace_url}/api/2.0/vector-search/endpoints/ep/indexes/i")

    @patch("databricks.vector_search.client.RequestUtils.issue_request")
    def test_delete_index_url_without_endpoint(self, mock_req, vsc_with_pat, workspace_url):
        mock_req.return_value = {}
        vsc_with_pat.delete_index(index_name="i")
        assert mock_req.call_args.kwargs["url"] == (f"{workspace_url}/api/2.0/vector-search/indexes/i")

    @patch("databricks.vector_search.client.RequestUtils.issue_request")
    def test_update_index_budget_policy_payload(self, mock_req, vsc_with_pat, workspace_url):
        mock_req.return_value = {}
        vsc_with_pat.update_index_budget_policy("i", usage_policy_id="up")
        call = mock_req.call_args.kwargs
        assert call["method"] == "PATCH"
        assert call["url"] == (f"{workspace_url}/api/2.0/vector-search/indexes/i/usage-policy")
        assert call["json"] == {"usage_policy_id": "up"}

    def test_update_index_budget_policy_rejects_both(self, vsc_with_pat):
        with pytest.raises(InvalidInputException):
            vsc_with_pat.update_index_budget_policy("i", budget_policy_id="b", usage_policy_id="u")


class TestPrivateHelpers:
    def test_get_index_url_with_endpoint(self, vsc_with_pat, workspace_url):
        assert vsc_with_pat._get_index_url("ep", "i") == (
            f"{workspace_url}/api/2.0/vector-search/endpoints/ep/indexes/i"
        )

    def test_get_index_url_without_endpoint(self, vsc_with_pat, workspace_url):
        assert vsc_with_pat._get_index_url(None, "i") == (f"{workspace_url}/api/2.0/vector-search/indexes/i")

    def test_mlserving_endpoint_name_from_resp(self, vsc_with_pat):
        resp = {"delta_sync_index_spec": {"embedding_source_columns": [{"embedding_model_endpoint_name": "my-ep"}]}}
        assert vsc_with_pat._get_mlserving_endpoint_name_from_resp(resp) == "my-ep"

    def test_mlserving_endpoint_name_for_query_from_resp(self, vsc_with_pat):
        resp = {"delta_sync_index_spec": {"embedding_source_columns": [{"model_endpoint_name_for_query": "query-ep"}]}}
        assert vsc_with_pat._get_mlserving_endpoint_name_for_query_from_resp(resp) == "query-ep"
